int countPermutations(int n, int k, int qq[])
{

const int N = 505, P = 998244353;
int q[N], m, dp[N][N], jc[N], f[N], ans;

memset(q, 0, sizeof(q));
memset(dp, 0, sizeof(dp));
memset(jc, 0, sizeof(jc));
memset(f, 0, sizeof(f));
ans = 0;

for (int i = 1; i <= n; i++)

q[i] = qq[i - 1];

dp[0][0] = f[0] = 1;
## START INFILLING
for (int i = 1; i <= n; i++)
{

f[i] = f[i - 1];
}

for (int i = 1; i <= n; i++)

{

for (int j = 0; j < i; j++)

for (int k = 1; k <= n; k++)

dp[i][k] = (dp[i][k] + dp[j][k - 1] * 1LL * f[i - j] % P) % P;
}
## END INFILLING
m = 0;
for (int i = 1; i <= n; i++)

if (q[i] > q[i + 1])
{

m = i;
break;
}

if (m == n)
{

for (int i = k; i <= n; i++)

ans = (ans + dp[n][i]) % P;
}
else
{

for (int i = m + 1; i <= n; i++)
{

if (i != m + 1 && (q[i - 1] > q[i] || q[i] < q[m]))

break;

int c = k + i - n - 1;
if (c >= 0)

ans = (ans + dp[m][c] * 1LL * jc[i - m - 1] % P) % P;
}
}

return ans;
}

